  // Lógica de Scroll Snapping para fixar a leitura nas etapas principais
  const timeoutRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    const handleScrollSnap = () => {
      if (!portalRef.current) return;

      const rect = portalRef.current.getBoundingClientRect();
      const totalScrollable = rect.height - window.innerHeight;

      // Se não estivermos completamente dentro da seção (topo já passou e base ainda não chegou), não faça snap
      if (rect.top > 0 || rect.bottom < window.innerHeight) return;

      if (timeoutRef.current) clearTimeout(timeoutRef.current);

      timeoutRef.current = setTimeout(() => {
        const targets = [0.22, 0.45, 0.68, 0.88];
        const currentProgress = Math.abs(rect.top) / totalScrollable;

        let nearestTarget = targets[0];
        let minDiff = Infinity;

        targets.forEach(t => {
           const diff = Math.abs(t - currentProgress);
           if (diff < minDiff) {
               minDiff = diff;
               nearestTarget = t;
           }
        });

        // Se a diferença for pequena, mas não exata, faça o snap suave
        if (minDiff > 0.005 && minDiff < 0.12) { 
          window.scrollTo({
             top: window.scrollY + rect.top + nearestTarget * totalScrollable,
             behavior: 'smooth'
          });
        }
      }, 150); // Espera 150ms após o scroll parar
    };

    window.addEventListener('scroll', handleScrollSnap, { passive: true });
    return () => {
      window.removeEventListener('scroll', handleScrollSnap);
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
    }
  }, []);","StartLi
